UPDATE patterns
SET definition = jsonb_set(definition, '{scorecard}', '{"max_score":90,"primary_threshold":75,"high_confidence_threshold":85,"criteria":[{"key":"trend_strength","label":"선행 상승 추세","max_points":20,"description":"최근 25거래일 저점 대비 30% 이상 상승하면 20점입니다."},{"key":"ma_distance","label":"이동평균선 이격도","max_points":25,"description":"조정 구간 저점 또는 조정확정일 종가가 5/10/20/60일선 중 하나와 플러스마이너스 2% 이내에 있습니다."},{"key":"pullback_duration","label":"조정 기간","max_points":10,"description":"확정봉 기준 최근 20거래일 안에서 가장 높은 종가 봉 다음 봉부터 확정봉까지를 조정 구간으로 보며, 20거래일 이하만 허용합니다."},{"key":"lower_wick","label":"아래꼬리 확인","max_points":15,"description":"조정확정일 봉의 아래꼬리 비율이 35% 이상이어야 합니다. 양봉은 시가-저가, 음봉은 종가-저가를 전체 봉 길이로 나눕니다."},{"key":"volume_dry_up","label":"조정 거래량 감소","max_points":15,"description":"조정 구간 평균 거래량이 선행 상승 구간보다 줄어듭니다."},{"key":"ma_structure","label":"이동평균선 구조","max_points":5,"description":"단기 이동평균선이 중기 이동평균선 위에 있거나 상승 중입니다."}]}'::jsonb, true),
    updated_at = now()
WHERE slug = 'pullback';

UPDATE patterns
SET definition = jsonb_set(definition, '{scorecard}', '{"max_score":100,"primary_threshold":75,"high_confidence_threshold":85,"criteria":[{"key":"prior_uptrend","label":"선행 상승 추세","max_points":15,"description":"1차 국소 고점 전 2~5주 주봉 종가 기준 상승률이 30% 이상이어야 합니다."},{"key":"contraction_count","label":"국소 고점/수축 횟수","max_points":10,"description":"국소 고점은 최소 3개 이상이어야 하며, 종가 기준 수축 구간은 2~5회 확인되어야 합니다."},{"key":"contraction_depths","label":"수축폭 감소","max_points":25,"description":"1차 -45%, 2차 -33%, 3차 -25%, 4차 -15%, 5차 -8% 한도 안에서 뒤로 갈수록 수축폭이 작아져야 합니다."},{"key":"volume_dry_up","label":"거래량 감소","max_points":15,"description":"수축이 진행될수록 거래량이 줄어들면 점수가 높습니다."},{"key":"last_contraction_quality","label":"마지막 수축 품질","max_points":15,"description":"마지막 수축은 좁고 짧을수록 좋으며, 5차 수축은 최대 -8%까지만 허용합니다."},{"key":"ma_structure","label":"이동평균선 정배열","max_points":10,"description":"주봉 MA10 > MA30 > MA40 정배열 상태여야 합니다."},{"key":"pivot_quality","label":"피벗 돌파 품질","max_points":10,"description":"피벗 돌파봉 거래량이 직전 봉 대비 150% 이상이어야 하며, 윗꼬리는 짧을수록 점수가 높습니다."}]}'::jsonb, true),
    updated_at = now()
WHERE slug = 'triangle';

UPDATE patterns
SET definition = jsonb_set(definition, '{scorecard}', '{"max_score":100,"primary_threshold":75,"high_confidence_threshold":85,"criteria":[{"key":"surge_strength","label":"선행 급등 강도","max_points":25,"description":"주봉 4~8주 안에 저점 종가 대비 고점봉 종가가 80~100% 이상 급등해야 합니다."},{"key":"surge_volume","label":"선행 급등 거래량","max_points":15,"description":"급등 구간 평균 거래량이 직전 평균 대비 150% 이상 증가해야 합니다."},{"key":"flag_depth","label":"깃발 조정 깊이","max_points":20,"description":"급등 고점봉 종가 대비 조정 구간 최저 종가 낙폭이 20% 이내여야 합니다."},{"key":"ma10_touch","label":"10주선 근접","max_points":15,"description":"조정 구간 중 종가가 MA10주 플러스마이너스 5% 안으로 처음 들어온 봉을 문제 마지막 봉으로 봅니다."},{"key":"volume_spike_control","label":"조정 거래량 급증 제한","max_points":15,"description":"조정 구간의 각 봉 거래량이 직전 봉 거래량의 200%를 넘지 않아야 합니다."},{"key":"ma10_support","label":"10주선 방어","max_points":10,"description":"조정 구간 종가가 MA10주보다 5% 이상 아래로 하락하면 후보에서 제외합니다."}]}'::jsonb, true),
    updated_at = now()
WHERE slug = 'flag';

UPDATE patterns
SET definition = jsonb_set(definition, '{scorecard}', '{"max_score":100,"primary_threshold":75,"high_confidence_threshold":85,"criteria":[{"key":"prior_uptrend","label":"선행 상승","max_points":20,"description":"VCP와 동일하게 선행 고점 전 2~5주 주봉 종가 기준 상승률이 30% 이상이어야 합니다."},{"key":"base_depth","label":"베이스 조정폭","max_points":20,"description":"베이스 구간의 종가 기준 최대 조정폭은 선행 상승 고점 종가 대비 15% 이내여야 합니다."},{"key":"three_week_tightness","label":"3주 종가 압축","max_points":25,"description":"거래량이 0이 아닌 주봉 3개가 종가 기준 1.5% 이내로 움직이면 플랫베이스 핵심 조건을 충족합니다."},{"key":"last_candle_rule","label":"문제 마지막 봉","max_points":10,"description":"3주 종가 압축이 완성되는 세 번째 주봉을 문제의 마지막 봉으로 사용합니다."},{"key":"ma_structure","label":"10/30/40주선 구조","max_points":15,"description":"주봉 차트에는 MA10, MA30, MA40을 표시하고 상승 추세에 어울리는 배열일수록 점수가 높습니다."},{"key":"volume_control","label":"거래량 안정","max_points":10,"description":"베이스 구간에서 과도한 매물 출회 없이 거래량이 안정될수록 점수가 높습니다."}]}'::jsonb, true),
    updated_at = now()
WHERE slug = 'flat-base';

UPDATE patterns
SET definition = jsonb_set(definition, '{scorecard}', '{"max_score":100,"primary_threshold":75,"high_confidence_threshold":85,"criteria":[{"key":"engulfing_completion","label":"몸통 장악 완성도","max_points":25,"description":"양봉 시가가 음봉 종가 이하이고 양봉 종가가 음봉 시가 이상이어야 하며, 장악 여유율이 클수록 점수가 높습니다."},{"key":"body_ratio","label":"장악 강도","max_points":15,"description":"양봉 몸통 크기 / 음봉 몸통 크기 비율이 클수록 점수가 높고, 1.0배 미만은 제외합니다."},{"key":"location_drawdown","label":"52주 신고가 대비 하락률","max_points":20,"description":"음봉 시작일 이전 252거래일 최고 종가 대비 20% 이상 하락한 위치에서 발생해야 합니다."},{"key":"bearish_wick_quality","label":"음봉 꼬리 품질","max_points":20,"description":"음봉 윗꼬리와 아래꼬리 비율의 합이 작을수록 점수가 높고 30% 초과는 제외합니다."},{"key":"bullish_wick_quality","label":"양봉 꼬리 품질","max_points":20,"description":"양봉 윗꼬리와 아래꼬리 비율의 합이 작을수록 점수가 높고 30% 초과는 제외합니다."}]}'::jsonb, true),
    updated_at = now()
WHERE slug = 'bullish-engulfing';

UPDATE patterns
SET definition = jsonb_set(definition, '{scorecard}', '{"max_score":100,"primary_threshold":75,"high_confidence_threshold":85,"criteria":[{"key":"volume_ratio","label":"거래량 배율","max_points":25,"description":"거래량이 최근 20일 평균 대비 200/300/500% 이상으로 증가합니다."},{"key":"price_response","label":"가격 반응","max_points":20,"description":"거래량 급증 봉 종가가 전일 대비 5% 이상 상승하거나 주요 가격대를 회복합니다."},{"key":"close_quality","label":"종가 위치 품질","max_points":15,"description":"종가가 고가 근처에 있고 윗꼬리가 과도하지 않습니다."},{"key":"breakout_context","label":"가격대 돌파 맥락","max_points":15,"description":"최근 20거래일 고점 또는 50일선을 함께 돌파하면 점수가 높습니다."},{"key":"base_context","label":"이전 눌림/횡보","max_points":10,"description":"급증 전 10~30거래일 동안 과열보다 준비 구간이 존재합니다."},{"key":"ma_recovery","label":"이동평균선 회복","max_points":10,"description":"거래량 급증 봉 종가가 50일선 위에 있습니다."},{"key":"risk_control","label":"꼬리/갭 리스크 제한","max_points":5,"description":"긴 윗꼬리와 과도한 갭 상승을 감점합니다."}]}'::jsonb, true),
    updated_at = now()
WHERE slug = 'volume-spike';
